document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("toc");if(!e)return;const t=document.querySelectorAll("h2, h3"),n=new IntersectionObserver(t=>{t.forEach(t=>{if(!t.isIntersecting)return;const n=t.target.id,s=e.querySelector(`a[href="#${n}"]`);if(!s)return;const o=s.parentElement;console.log(n),e.querySelectorAll("li.active").forEach(e=>e.classList.remove("active")),o.classList.add("active");const i=o.closest("ul").previousElementSibling?.closest("li");i&&i.classList.add("active")})},{rootMargin:"0px 0px -75% 0px",threshold:.5});t.forEach(e=>n.observe(e))})